void check(char *username, char *serial) {
    int len = strlen(username);
    char expected[256];
    for (int i=0; i<len; i++) {
        expected[i] = username[i] + 0x20;
    }
    expected[len] = 0;
    if (strcmp(serial, expected) == 0) {
